import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.TermsAggregationBuilder;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.springframework.stereotype.Repository;

import java.io.IOException;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@Repository
public class ElasticsearchRepository {

    public static final String PRODUCT_INDEX = "products";
    public static final String SEARCH_LOG_INDEX = "search_queries";

    private final RestHighLevelClient client;

    public ElasticsearchRepository(RestHighLevelClient client) {
        this.client = client;
    }

    public boolean indexExists(String index) throws IOException {
        GetIndexRequest request = new GetIndexRequest(index);
        return client.indices().exists(request, RequestOptions.DEFAULT);
    }

    public void createProductIndex() throws IOException {
        if (indexExists(PRODUCT_INDEX)) {
            return;
        }
        CreateIndexRequest request = new CreateIndexRequest(PRODUCT_INDEX);
        request.mapping(createProductMapping());
        client.indices().create(request, RequestOptions.DEFAULT);
    }

    public void createSearchLogIndex() throws IOException {
        if (indexExists(SEARCH_LOG_INDEX)) {
            return;
        }
        CreateIndexRequest request = new CreateIndexRequest(SEARCH_LOG_INDEX);
        request.mapping(createSearchLogMapping());
        client.indices().create(request, RequestOptions.DEFAULT);
    }

    public IndexResponse indexProduct(Product product) throws IOException {
        IndexRequest request = new IndexRequest(PRODUCT_INDEX).id(product.getId()).source(toProductSource(product));
        return client.index(request, RequestOptions.DEFAULT);
    }

    public BulkResponse bulkIndexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        for (Product product : products) {
            bulkRequest.add(new IndexRequest(PRODUCT_INDEX).id(product.getId()).source(toProductSource(product)));
        }
        return client.bulk(bulkRequest, RequestOptions.DEFAULT);
    }

    public IndexResponse indexSearchLog(SearchQueryLog log) throws IOException {
        IndexRequest request = new IndexRequest(SEARCH_LOG_INDEX).id(log.getId()).source(toSearchLogSource(log));
        return client.index(request, RequestOptions.DEFAULT);
    }

    public SearchResponse search(SearchRequest searchRequest) throws IOException {
        return client.search(searchRequest, RequestOptions.DEFAULT);
    }

    private Map<String, Object> toProductSource(Product product) {
        Map<String, Object> source = new HashMap<>();
        source.put("name", product.getName());
        source.put("description", product.getDescription());
        source.put("brand", product.getBrand());
        source.put("category", product.getCategory());
        source.put("tags", product.getTags());
        source.put("sku", product.getSku());
        source.put("price", product.getPrice());
        source.put("currency", product.getCurrency());
        source.put("stock", product.getStock());
        source.put("rating", product.getRating());
        source.put("attributes", product.getAttributes());
        source.put("createdAt", product.getCreatedAt());
        source.put("updatedAt", product.getUpdatedAt());
        return source;
    }

    private Map<String, Object> toSearchLogSource(SearchQueryLog log) {
        Map<String, Object> source = new HashMap<>();
        source.put("query", log.getQuery());
        source.put("userId", log.getUserId());
        source.put("filters", log.getFilters());
        source.put("timestamp", log.getTimestamp());
        source.put("resultCount", log.getResultCount());
        return source;
    }

    private XContentBuilder createProductMapping() throws IOException {
        return XContentFactory.jsonBuilder()
                .startObject()
                    .startObject("properties")
                        .startObject("name").field("type", "text").field("analyzer", "standard").endObject()
                        .startObject("description").field("type", "text").field("analyzer", "standard").endObject()
                        .startObject("brand").field("type", "keyword").endObject()
                        .startObject("category").field("type", "keyword").endObject()
                        .startObject("tags").field("type", "keyword").endObject()
                        .startObject("sku").field("type", "keyword").endObject()
                        .startObject("price").field("type", "double").endObject()
                        .startObject("currency").field("type", "keyword").endObject()
                        .startObject("stock").field("type", "integer").endObject()
                        .startObject("rating").field("type", "double").endObject()
                        .startObject("attributes").field("type", "object").endObject()
                        .startObject("createdAt").field("type", "date").endObject()
                        .startObject("updatedAt").field("type", "date").endObject()
                    .endObject()
                .endObject();
    }

    private XContentBuilder createSearchLogMapping() throws IOException {
        return XContentFactory.jsonBuilder()
                .startObject()
                    .startObject("properties")
                        .startObject("query").field("type", "text").endObject()
                        .startObject("userId").field("type", "keyword").endObject()
                        .startObject("filters").field("type", "object").endObject()
                        .startObject("timestamp").field("type", "date").endObject()
                        .startObject("resultCount").field("type", "integer").endObject()
                    .endObject()
                .endObject();
    }
}

package com.example.ecomsearch.service;

import com.example.ecomsearch.dto.*;
import com.example.ecomsearch.model.Product;
import com.example.ecomsearch.model.SearchQueryLog;
import com.example.ecomsearch.repository.ElasticsearchRepository;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.Aggregation;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.aggregations.metrics.ParsedStats;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.index.query.RangeQueryBuilder;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.index.query.Operator;
import org.elasticsearch.search.fetch.subphase.FetchSourceContext;
import org.elasticsearch.search.sort.SortOrder;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class ProductSearchService {

    private final ElasticsearchRepository repository;

    public ProductSearchService(ElasticsearchRepository repository) {
        this.repository = repository;
    }

    public void initialize() throws IOException {
        repository.createProductIndex();
        repository.createSearchLogIndex();
    }

    public ProductResponse indexProduct(ProductRequest request, String id) throws IOException {
        Instant now = Instant.now();
        Product product = new Product(
                id,
                request.getName(),
                request.getDescription(),
                request.getBrand(),
                request.getCategory(),
                request.getTags(),
                request.getSku(),
                request.getPrice(),
                request.getCurrency(),
                request.getStock(),
                request.getRating(),
                request.getAttributes(),
                now,
                now
        );
        repository.indexProduct(product);
        return toResponse(product);
    }

    public SearchResponse searchProducts(SearchRequest request, String userId) throws IOException {
        int page = request.getPage() == null || request.getPage() < 0 ? 0 : request.getPage();
        int size = request.getSize() == null || request.getSize() <= 0 ? 10 : request.getSize();

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (request.getQuery() != null && !request.getQuery().isBlank()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(request.getQuery(), "name", "description", "brand", "category", "tags", "sku")
                    .operator(Operator.AND));
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (request.getCategory() != null && !request.getCategory().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("category", request.getCategory()));
        }

        if (request.getBrand() != null && !request.getBrand().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("brand", request.getBrand()));
        }

        if (request.getTags() != null && !request.getTags().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("tags", request.getTags()));
        }

        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            RangeQueryBuilder rangeQuery = QueryBuilders.rangeQuery("price");
            if (request.getMinPrice() != null) {
                rangeQuery.gte(request.getMinPrice());
            }
            if (request.getMaxPrice() != null) {
                rangeQuery.lte(request.getMaxPrice());
            }
            boolQuery.filter(rangeQuery);
        }

        sourceBuilder.query(boolQuery);
        sourceBuilder.from(page * size);
        sourceBuilder.size(size);
        sourceBuilder.fetchSource(new String[]{"name", "description", "brand", "category", "tags", "sku", "price", "currency", "stock", "rating", "attributes"}, null);
        sourceBuilder.aggregation(AggregationBuilders.terms("brand_facet").field("brand").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("category_facet").field("category").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("tags_facet").field("tags").size(20));
        sourceBuilder.aggregation(AggregationBuilders.stats("price_stats").field("price"));
        sourceBuilder.sort("rating", SortOrder.DESC);
        sourceBuilder.sort("price", SortOrder.ASC);

        org.elasticsearch.action.search.SearchRequest esRequest = new org.elasticsearch.action.search.SearchRequest(ElasticsearchRepository.PRODUCT_INDEX);
        esRequest.source(sourceBuilder);

        SearchResponse response = repository.search(esRequest);

        List<ProductResponse> products = new ArrayList<>();
        for (SearchHit hit : response.getHits().getHits()) {
            Map<String, Object> source = hit.getSourceAsMap();
            products.add(new ProductResponse(
                    hit.getId(),
                    (String) source.get("name"),
                    (String) source.get("description"),
                    (String) source.get("brand"),
                    (String) source.get("category"),
                    castStringList(source.get("tags")),
                    (String) source.get("sku"),
                    source.get("price") == null ? null : new java.math.BigDecimal(source.get("price").toString()),
                    (String) source.get("currency"),
                    source.get("stock") == null ? null : ((Number) source.get("stock")).intValue(),
                    source.get("rating") == null ? null : ((Number) source.get("rating")).doubleValue(),
                    castStringMap(source.get("attributes"))
            ));
        }

        Map<String, List<FacetBucket>> facets = new HashMap<>();
        facets.put("brand", extractTermsFacet(response, "brand_facet"));
        facets.put("category", extractTermsFacet(response, "category_facet"));
        facets.put("tags", extractTermsFacet(response, "tags_facet"));

        SearchQueryLog log = new SearchQueryLog(
                UUID.randomUUID().toString(),
                request.getQuery(),
                userId,
                buildFilterMap(request),
                Instant.now(),
                (int) response.getHits().getTotalHits().value
        );
        repository.indexSearchLog(log);

        return new SearchResponse(response.getHits().getTotalHits().value, products, facets);
    }

    private List<FacetBucket> extractTermsFacet(SearchResponse response, String aggregationName) {
        Aggregation aggregation = response.getAggregations().get(aggregationName);
        if (aggregation == null) {
            return Collections.emptyList();
        }
        Terms terms = (Terms) aggregation;
        return terms.getBuckets().stream()
                .map(bucket -> new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()))
                .collect(Collectors.toList());
    }

    private ProductResponse toResponse(Product product) {
        return new ProductResponse(
                product.getId(),
                product.getName(),
                product.getDescription(),
                product.getBrand(),
                product.getCategory(),
                product.getTags(),
                product.getSku(),
                product.getPrice(),
                product.getCurrency(),
                product.getStock(),
                product.getRating(),
                product.getAttributes()
        );
    }

    private List<String> castStringList(Object value) {
        if (value == null) {
            return Collections.emptyList();
        }
        if (value instanceof List<?>) {
            List<?> list = (List<?>) value;
            return list.stream().map(Object::toString).collect(Collectors.toList());
        }
        return Collections.singletonList(value.toString());
    }

    private Map<String, String> castStringMap(Object value) {
        if (value == null) {
            return Collections.emptyMap();
        }
        if (value instanceof Map<?, ?>) {
            Map<?, ?> map = (Map<?, ?>) value;
            Map<String, String> result = new HashMap<>();
            for (Map.Entry<?, ?> entry : map.entrySet()) {
                result.put(String.valueOf(entry.getKey()), String.valueOf(entry.getValue()));
            }
            return result;
        }
        return Collections.emptyMap();
    }

    private Map<String, Object> buildFilterMap(SearchRequest request) {
        Map<String, Object> filters = new HashMap<>();
        if (request.getCategory() != null) filters.put("category", request.getCategory());
        if (request.getBrand() != null) filters.put("brand", request.getBrand());
        if (request.getTags() != null) filters.put("tags", request.getTags());
        if (request.getMinPrice() != null) filters.put("minPrice", request.getMinPrice());
        if (request.getMaxPrice() != null) filters.put("maxPrice", request.getMaxPrice());
        return filters;
    }
}

package com.example.ecomsearch.controller;

import com.example.ecomsearch.dto.ProductRequest;
import com.example.ecomsearch.dto.ProductResponse;
import com.example.ecomsearch.dto.SearchRequest;
import com.example.ecomsearch.dto.SearchResponse;
import com.example.ecomsearch.service.ProductSearchService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.UUID;

@RestController
@RequestMapping("/api")
public class SearchController {

    private final ProductSearchService service;

    public SearchController(ProductSearchService service) {
        this.service = service;
    }

    @PostMapping("/products")
    public ResponseEntity<ProductResponse> indexProduct(@RequestBody ProductRequest request) throws IOException {
        String id = UUID.randomUUID().toString();
        return ResponseEntity.ok(service.indexProduct(request, id));
    }

    @PostMapping("/search")
    public ResponseEntity<SearchResponse> search(@RequestBody SearchRequest request, @RequestHeader(value = "X-User-Id", required = false) String userId) throws IOException {
        return ResponseEntity.ok(service.searchProducts(request, userId == null ? "anonymous" : userId));
    }

    @PostMapping("/init")
    public ResponseEntity<String> initialize() throws IOException {
        service.initialize();
        return ResponseEntity.ok("initialized");
    }
}